const crypto = require('crypto');

// --- 1. Парсим тело ---
let body;
try {
  const raw = $input.first().json.body;
  body = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  throw new Error('Invalid JSON body');
}

const initData = body.initData || '';
if (!initData) throw new Error('Missing initData');

// --- 2. HMAC-валидация initData по схеме Telegram WebApp ---
const botToken = $input.first().json.bot_token;
if (!botToken) throw new Error('TELEGRAM_BOT_TOKEN env var not set');

// Парсим initData вручную (URLSearchParams недоступен в JS Task Runner sandbox)
const pairs = initData.split('&').map(p => {
  const i = p.indexOf('=');
  return i === -1 ? [p, ''] : [decodeURIComponent(p.slice(0, i)), decodeURIComponent(p.slice(i + 1))];
});
const paramsMap = new Map(pairs);
const hash = paramsMap.get('hash');
paramsMap.delete('hash');

const dataCheckString = [...paramsMap.entries()]
  .sort(([a], [b]) => a.localeCompare(b))
  .map(([k, v]) => `${k}=${v}`)
  .join('\n');

const secretKey = crypto.createHmac('sha256', 'WebAppData').update(botToken).digest();
const computed = crypto.createHmac('sha256', secretKey).update(dataCheckString).digest('hex');

if (computed !== hash) {
  throw new Error('Invalid initData signature');
}

// --- 3. Авторизация: дата initData не старше суток ---
const authDate = Number(paramsMap.get('auth_date')) || 0;
const nowSec = Math.floor(Date.now() / 1000);
if (nowSec - authDate > 86400) {
  throw new Error('initData too old (>24h)');
}

// --- 4. Извлекаем юзера ---
let user;
try { user = JSON.parse(paramsMap.get('user')); }
catch { throw new Error('Cannot parse user from initData'); }
if (!user || !user.id) throw new Error('No user.id in initData');

const chat_id = String(user.id);

// --- 5. Дата/время Москвы, meal_type по часу ---
const now = new Date();
// смещение Москвы +3ч; Date в n8n уже в TZ контейнера (Europe/Moscow), но подстрахуемся:
const pad = (n) => String(n).padStart(2, '0');
const date = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}`;
const time = `${pad(now.getHours())}:${pad(now.getMinutes())}`;
const h = now.getHours();
let meal_type;
if      (h < 11) meal_type = 'завтрак';
else if (h < 16) meal_type = 'обед';
else if (h < 19) meal_type = 'перекус';
else if (h < 24) meal_type = 'ужин';
else             meal_type = 'перекус';

return [{
  json: {
    chat_id,
    user_name: user.first_name || '',
    date,
    time,
    meal_type,
    payload: body,
  }
}];

// Возвращает план тренировки на сегодня + статус галочек (workout_done).
// expected_today считается так же, как в Build Context / дашборде.
const v = $('Validate & Parse').first().json;
const chat_id = String(v.chat_id);
const today = v.date;

const profileRows = $('Read Profile').all().map(i => i.json);
const profileRow = profileRows.find(r => String(r.chat_id) === chat_id) || profileRows[0] || null;
const interval = Number(profileRow?.training_days_interval) || 1;

const workoutRows = $('Read Workout Log').all().map(i => i.json);
const sortedW = workoutRows.filter(r => r.date).sort((a, b) => String(a.date).localeCompare(String(b.date)));
const lastWorkout = sortedW[sortedW.length - 1] || null;

const blocksStateRows = $('Read Workout Blocks').all().map(i => i.json);
const blocksState = {};
for (const r of blocksStateRows) {
  const n = Number(r.block_num); if (!n) continue;
  blocksState[n] = { label: r.label || `№${n}`, active: String(r.active).toUpperCase() === 'TRUE' };
}
if (!Object.keys(blocksState).length) { for (const n of [1,2,3,4]) blocksState[n] = { label: `№${n}`, active: true }; }
const activeNums = Object.keys(blocksState).map(Number).filter(n => blocksState[n].active).sort((a,b)=>a-b);

function nextActiveAfter(lastN, active) { if (!active.length) return null; const after = active.find(n => n > lastN); return after != null ? after : active[0]; }
function parseWorkoutNumber(plan) {
  if (!plan) return null;
  const m = String(plan).match(/№?\s*([1-4])/); if (m) return Number(m[1]);
  const s = String(plan).toLowerCase();
  if (s.includes('грудь') && s.includes('бицепс')) return 1;
  if (s.includes('плечи') && s.includes('грудь')) return 2;
  if (s.includes('спина') && s.includes('трицепс')) return 3;
  if (s.includes('ноги')) return 4;
  return null;
}

let expected_today;
if (!activeNums.length) expected_today = { type: 'rest', days_until_next: null };
else if (!lastWorkout) { const n = activeNums[0]; expected_today = { type: 'workout', number: n, label: blocksState[n].label }; }
else {
  const daysSince = Math.floor((new Date(today) - new Date(String(lastWorkout.date))) / (1000*60*60*24));
  if (daysSince < interval) expected_today = { type: 'rest', days_until_next: interval - daysSince };
  else { const lastN = parseWorkoutNumber(lastWorkout.day_plan) || 0; const nextN = nextActiveAfter(lastN, activeNums); expected_today = { type: 'workout', number: nextN, label: blocksState[nextN].label }; }
}

if (expected_today.type !== 'workout') {
  return [{ json: { ok: true, date: today, is_workout: false, label: null, block_num: null,
    days_until_next: expected_today.days_until_next ?? null, exercises: [] } }];
}

const block = expected_today.number;

// Галочки за сегодня по этому блоку
const doneRows = $('Read Workout Done').all().map(i => i.json);
const doneSet = new Set(
  doneRows
    .filter(r => String(r.date) === today && Number(r.block_num) === block && String(r.done).toUpperCase() === 'TRUE')
    .map(r => String(r.exercise).trim())
);

const wkRows = $('Read Workouts Catalog').all().map(i => i.json);
const exercises = [];
for (const r of wkRows) {
  if (Number(r.block_num) !== block) continue;
  if (!r.exercise) continue;
  const ex = String(r.exercise).trim();
  exercises.push({
    id: `${block}::${ex}`,
    group: r.group || '',
    exercise: ex,
    sets: r.sets != null ? String(r.sets) : '',
    reps: r.reps != null ? String(r.reps) : '',
    weight: (r.weight != null && r.weight !== '—') ? String(r.weight) : '',
    note: r.note || '',
    done: doneSet.has(ex),
  });
}

return [{ json: { ok: true, date: today, is_workout: true,
  label: expected_today.label, block_num: block, exercises } }];
